export interface UserProfile {
  name: string;
  annualIncome: number;
  creditScore: number;
  monthlySpend: number;
  topCategories: string[];
  primaryGoal: 'travel' | 'cashback' | 'balance_transfer' | 'luxury';
}

export interface CreditCardRecommendation {
  cardName: string;
  bankName: string;
  matchScore: number;
  annualFee: string;
  features: string[];
  colorTheme: string; // Hex code or tailwind class hint
  reasoning: string;
}

export enum CardType {
  TRAVEL = 'TRAVEL',
  CASHBACK = 'CASHBACK',
  LUXURY = 'LUXURY',
  BUILDER = 'BUILDER'
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, CreditCardRecommendation } from '../types';

// Initialize Gemini
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getRecommendations = async (profile: UserProfile): Promise<CreditCardRecommendation[]> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Act as a senior financial analyst and credit card expert.
    Analyze the following user profile:
    - Name: ${profile.name}
    - Annual Income: $${profile.annualIncome}
    - Credit Score: ${profile.creditScore}
    - Monthly Spending: $${profile.monthlySpend}
    - Top Spending Categories: ${profile.topCategories.join(', ')}
    - Primary Goal: ${profile.primaryGoal}

    Based on this, recommend 3 distinct credit cards that perfectly match their lifestyle.
    You can generate realistic fictional card names (e.g., "Sapphire Horizon", "Onyx Reserve") if you want to avoid specific brand bias, or use well-known real-world archetypes.

    Provide the response strictly in JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              cardName: { type: Type.STRING },
              bankName: { type: Type.STRING },
              matchScore: { type: Type.NUMBER, description: "Percentage match 0-100" },
              annualFee: { type: Type.STRING },
              features: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              colorTheme: { type: Type.STRING, description: "A hex color code representing the card's branding" },
              reasoning: { type: Type.STRING, description: "Why this card fits the user" }
            },
            required: ["cardName", "bankName", "matchScore", "annualFee", "features", "colorTheme", "reasoning"]
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText) as CreditCardRecommendation[];
  } catch (error) {
    console.error("Error fetching recommendations:", error);
    // Fallback or rethrow
    return [];
  }
};

import React, { useRef, useState, MouseEvent } from 'react';

interface TiltCardProps {
  children: React.ReactNode;
  className?: string;
  glowColor?: string;
}

export const TiltCard: React.FC<TiltCardProps> = ({ children, className = "", glowColor = "rgba(99, 102, 241, 0.4)" }) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [rotation, setRotation] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;

    const rect = cardRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    const rotateX = ((y - centerY) / centerY) * -10; // Invert X axis for correct tilt
    const rotateY = ((x - centerX) / centerX) * 10;

    setRotation({ x: rotateX, y: rotateY });
  };

  const handleMouseEnter = () => setIsHovered(true);
  const handleMouseLeave = () => {
    setIsHovered(false);
    setRotation({ x: 0, y: 0 });
  };

  return (
    <div
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className={`relative transition-all duration-200 ease-out transform-gpu ${className}`}
      style={{
        perspective: "1000px",
      }}
    >
      <div
        className="w-full h-full transition-transform duration-200 ease-out"
        style={{
          transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg) scale(${isHovered ? 1.05 : 1})`,
          transformStyle: "preserve-3d",
        }}
      >
        <div 
          className="absolute inset-0 rounded-2xl opacity-0 transition-opacity duration-300 pointer-events-none z-0"
          style={{
             opacity: isHovered ? 1 : 0,
             background: `radial-gradient(circle at 50% 50%, ${glowColor}, transparent 70%)`,
             filter: 'blur(20px)',
             transform: 'translateZ(-20px)'
          }}
        />
        <div className="relative z-10 h-full">
           {children}
        </div>

        {/* Gloss overlay */}
        <div 
            className="absolute inset-0 rounded-2xl pointer-events-none z-20 mix-blend-overlay"
            style={{
                background: `linear-gradient(125deg, rgba(255,255,255,0.4) 0%, transparent 40%, transparent 60%, rgba(255,255,255,0.1) 100%)`,
                opacity: isHovered ? 0.3 : 0,
                transition: 'opacity 0.3s ease'
            }}
        />
      </div>
    </div>
  );
};

