import React, { useState } from 'react';
import { UserProfile, CreditCardRecommendation } from '../types';
import { getRecommendations } from '../services/ai';
import { TiltCard } from './TiltCard';
import { Check, Loader2, DollarSign, PieChart, TrendingUp } from 'lucide-react';

const INITIAL_PROFILE: UserProfile = {
  name: '',
  annualIncome: 50000,
  creditScore: 700,
  monthlySpend: 2000,
  topCategories: [],
  primaryGoal: 'cashback'
};

const CATEGORIES = ['Dining', 'Travel', 'Groceries', 'Gas', 'Shopping', 'Entertainment', 'Utilities'];

export const RecommendationEngine: React.FC = () => {
  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<CreditCardRecommendation[]>([]);

  const handleInputChange = (field: keyof UserProfile, value: any) => {
    setProfile(prev => ({ ...prev, [field]: value }));
  };

  const toggleCategory = (cat: string) => {
    setProfile(prev => {
      const current = prev.topCategories;
      if (current.includes(cat)) {
        return { ...prev, topCategories: current.filter(c => c !== cat) };
      }
      if (current.length < 3) {
        return { ...prev, topCategories: [...current, cat] };
      }
      return prev;
    });
  };

  const handleSubmit = async () => {
    setLoading(true);
    setStep(3); // Loading State
    try {
      const recs = await getRecommendations(profile);
      setResults(recs);
      setStep(4); // Results State
    } catch (e) {
      console.error(e);
      setStep(1); // Reset on error
    } finally {
      setLoading(false);
    }
  };

  // Step 1: Financial Basics
  const renderStep1 = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-serif font-bold text-white mb-2">Financial Profile</h2>
        <p className="text-gray-400">Let's start with the basics to gauge your eligibility.</p>
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">Full Name</label>
          <input 
            type="text" 
            value={profile.name}
            onChange={(e) => handleInputChange('name', e.target.value)}
            className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            placeholder="e.g. John Doe"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">Annual Income ($)</label>
            <div className="relative">
              <DollarSign className="absolute left-3 top-3.5 w-4 h-4 text-gray-500" />
              <input 
                type="number" 
                value={profile.annualIncome}
                onChange={(e) => handleInputChange('annualIncome', parseInt(e.target.value))}
                className="w-full bg-white/5 border border-white/10 rounded-lg pl-10 pr-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">Credit Score</label>
            <div className="relative">
              <TrendingUp className="absolute left-3 top-3.5 w-4 h-4 text-gray-500" />
              <input 
                type="number" 
                value={profile.creditScore}
                max={850}
                onChange={(e) => handleInputChange('creditScore', parseInt(e.target.value))}
                className="w-full bg-white/5 border border-white/10 rounded-lg pl-10 pr-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
            </div>
          </div>
        </div>

        <button 
          onClick={() => setStep(2)}
          disabled={!profile.name}
          className="w-full py-4 mt-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-500/20"
        >
          Next: Spending Habits
        </button>
      </div>
    </div>
  );

  // Step 2: Habits & Goals
  const renderStep2 = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-serif font-bold text-white mb-2">Habits & Goals</h2>
        <p className="text-gray-400">Tell us how you spend and what you want to earn.</p>
      </div>

      <div className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-3">Top Spending Categories (Max 3)</label>
          <div className="flex flex-wrap gap-2">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => toggleCategory(cat)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                  profile.topCategories.includes(cat)
                    ? 'bg-indigo-500 text-white shadow-[0_0_10px_rgba(99,102,241,0.5)]'
                    : 'bg-white/5 text-gray-400 hover:bg-white/10'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-3">Primary Goal</label>
          <div className="grid grid-cols-2 gap-3">
            {[
              { id: 'cashback', label: 'Max Cashback' },
              { id: 'travel', label: 'Travel Rewards' },
              { id: 'luxury', label: 'Luxury Perks' },
              { id: 'balance_transfer', label: 'Build Credit' }
            ].map((goal) => (
              <button
                key={goal.id}
                onClick={() => handleInputChange('primaryGoal', goal.id)}
                className={`p-4 rounded-xl border transition-all text-left ${
                  profile.primaryGoal === goal.id
                    ? 'border-indigo-500 bg-indigo-500/10 text-white'
                    : 'border-white/10 bg-white/5 text-gray-400 hover:border-white/20'
                }`}
              >
                <div className="font-semibold">{goal.label}</div>
              </button>
            ))}
          </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={() => setStep(1)}
            className="flex-1 py-4 bg-white/5 hover:bg-white/10 text-gray-300 rounded-lg font-bold transition-all"
          >
            Back
          </button>
          <button 
            onClick={handleSubmit}
            className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-bold transition-all shadow-lg shadow-indigo-500/20"
          >
            Generate Recommendations
          </button>
        </div>
      </div>
    </div>
  );

  // Step 3: Loading
  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center py-20 text-center space-y-6 animate-fadeIn">
      <div className="relative">
        <div className="w-24 h-24 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin"></div>
        <div className="absolute inset-0 flex items-center justify-center">
          <PieChart className="w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
      </div>
      <div>
        <h3 className="text-2xl font-bold text-white mb-2">Analyzing Profile...</h3>
        <p className="text-gray-400">Our AI agent is scanning 50+ credit products for your best match.</p>
      </div>
    </div>
  );

  // Step 4: Results
  const renderResults = () => (
    <div className="space-y-12 animate-fadeIn w-full">
       <div className="text-center">
          <h2 className="text-4xl font-serif font-bold text-white mb-4">Your Perfect Matches</h2>
          <p className="text-gray-400 max-w-2xl mx-auto">Based on your income of ${profile.annualIncome} and spending habits in {profile.topCategories.join(', ')}.</p>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
         {results.map((card, idx) => (
           <div key={idx} className="flex flex-col h-full">
             <TiltCard className="w-full aspect-[1.586] mb-6 group" glowColor={card.colorTheme}>
               <div 
                className="w-full h-full rounded-2xl p-6 flex flex-col justify-between relative overflow-hidden border border-white/10 shadow-2xl"
                style={{ background: card.colorTheme || '#1e293b' }}
               >
                  <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-black/40 pointer-events-none"></div>
                  {/* Decorative chip */}
                  <div className="relative z-10 flex justify-between items-start">
                     <div className="w-10 h-7 bg-yellow-200/80 rounded opacity-90 backdrop-blur-sm" />
                     <span className="font-mono text-xs text-white/60">{card.bankName}</span>
                  </div>
                  <div className="relative z-10">
                    <h3 className="text-xl font-serif font-bold text-white mb-1 shadow-black drop-shadow-md">{card.cardName}</h3>
                    <div className="text-xs text-white/70 font-mono tracking-widest">•••• •••• •••• 4289</div>
                  </div>
               </div>
             </TiltCard>

             <div className="glass-panel rounded-2xl p-6 flex-1 flex flex-col border-t-2 border-t-indigo-500">
               <div className="flex justify-between items-center mb-4">
                 <div className="flex items-center gap-2">
                   <div className="w-8 h-8 rounded-full bg-green-500/20 flex items-center justify-center text-green-400 font-bold text-xs">
                     {card.matchScore}%
                   </div>
                   <span className="text-sm font-medium text-green-400">Match</span>
                 </div>
                 <span className="text-white font-bold">{card.annualFee} <span className="text-xs text-gray-500 font-normal">/yr</span></span>
               </div>

               <p className="text-gray-300 text-sm mb-4 italic">"{card.reasoning}"</p>

               <ul className="space-y-2 mb-6 flex-1">
                 {card.features.map((feat, i) => (
                   <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
                     <Check className="w-4 h-4 text-indigo-400 mt-0.5 shrink-0" />
                     {feat}
                   </li>
                 ))}
               </ul>

               <button className="w-full py-3 rounded-lg border border-white/20 hover:bg-white/10 text-white text-sm font-medium transition-colors">
                 Apply Now
               </button>
             </div>
           </div>
         ))}
       </div>

       <div className="flex justify-center pt-8">
         <button 
           onClick={() => { setStep(1); setResults([]); }}
           className="px-6 py-3 text-gray-400 hover:text-white transition-colors flex items-center gap-2"
         >
           Start Over
         </button>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen py-20 px-4 flex flex-col items-center justify-center bg-nova-dark relative">
      <div className="absolute top-0 left-0 w-full h-full bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none"></div>

      <div className="w-full max-w-4xl relative z-10">
        {step < 4 && (
          <div className="glass-panel rounded-2xl p-8 md:p-12 shadow-2xl relative overflow-hidden">
            {/* Progress Bar */}
            <div className="absolute top-0 left-0 w-full h-1 bg-white/10">
              <div 
                className="h-full bg-indigo-500 transition-all duration-500 ease-out"
                style={{ width: `${(step / 3) * 100}%` }}
              ></div>
            </div>

            {step === 1 && renderStep1()}
            {step === 2 && renderStep2()}
            {step === 3 && renderLoading()}
          </div>
        )}

        {step === 4 && renderResults()}
      </div>
    </div>
  );
};

