interface ComparisonTableProps {
  cards: CreditCardRecommendation[];
}

export const ComparisonTable: React.FC<ComparisonTableProps> = ({ cards }) => {
  // Find the highest match score to highlight that column
  const highestMatch = Math.max(...cards.map(c => c.matchScore));

  const highlightText = (text: string) => {
    // Basic heuristic to highlight beneficial terms
    const keywords = ['lifetime free', 'unlimited', 'free', 'bonus', 'complementary', '0 joining'];
    const lowerText = text.toLowerCase();

    // If it's a good number (like a high reward rate or low fee), we could check that too, 
    // but regex matching keywords is safer for general text.

    if (keywords.some(k => lowerText.includes(k))) {
      return <span className="text-green-400 font-semibold">{text}</span>;
    }
    return <span className="text-gray-300">{text}</span>;
  };

  return (
    <div className="w-full overflow-x-auto rounded-2xl glass-panel border border-white/10">
      <table className="w-full text-left border-collapse min-w-[800px]">
        <thead>
          <tr className="border-b border-white/10">
            <th className="p-6 text-gray-400 font-medium w-1/5 bg-white/5">Features</th>
            {cards.map((card, idx) => (
              <th key={idx} className={`p-6 w-1/5 relative ${card.matchScore === highestMatch ? 'bg-indigo-500/10' : ''}`}>
                {card.matchScore === highestMatch && (
                  <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-1 bg-yellow-500 text-black text-[10px] font-bold rounded-full flex items-center gap-1 shadow-lg shadow-yellow-500/20">
                     <Trophy className="w-3 h-3" />
                     RECOMMENDED
                  </div>
                )}
                <div className="flex flex-col gap-2 mt-2">
                    <span className="text-xs font-mono text-indigo-400">{card.bankName}</span>
                    <span className="text-lg font-bold text-white leading-tight">{card.cardName}</span>
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-white/5">
          {/* Annual Fee */}
          <tr className="hover:bg-white/5 transition-colors">
            <td className="p-6 font-medium text-gray-300">Annual Fee</td>
            {cards.map((card, idx) => (
              <td key={idx} className={`p-6 text-sm ${card.matchScore === highestMatch ? 'bg-indigo-500/5' : ''}`}>
                 {highlightText(card.annualFee)}
              </td>
            ))}
          </tr>

          {/* Match Score */}
          <tr className="hover:bg-white/5 transition-colors">
            <td className="p-6 font-medium text-gray-300">AI Match Score</td>
            {cards.map((card, idx) => (
              <td key={idx} className={`p-6 ${card.matchScore === highestMatch ? 'bg-indigo-500/5' : ''}`}>
                 <div className={`inline-flex items-center px-2 py-1 rounded-md text-sm font-bold ${
                     card.matchScore === highestMatch 
                     ? 'bg-green-500 text-white shadow-[0_0_10px_rgba(34,197,94,0.4)]' 
                     : 'bg-green-500/20 text-green-400'
                 }`}>
                    {card.matchScore}%
                 </div>
              </td>
            ))}
          </tr>

          {/* Reward Rate */}
          <tr className="hover:bg-white/5 transition-colors">
            <td className="p-6 font-medium text-gray-300">Reward Rate</td>
            {cards.map((card, idx) => (
              <td key={idx} className={`p-6 text-sm leading-relaxed ${card.matchScore === highestMatch ? 'bg-indigo-500/5' : ''}`}>
                 {highlightText(card.rewardRate)}
