              <td key={idx} className={`p-6 text-sm leading-relaxed ${card.matchScore === highestMatch ? 'bg-indigo-500/5' : ''}`}>
                 {highlightText(card.welcomeBonus)}
              </td>
            ))}
          </tr>

           {/* Credit Score Req */}
           <tr className="hover:bg-white/5 transition-colors">
            <td className="p-6 font-medium text-gray-300">Min. Credit Score</td>
            {cards.map((card, idx) => (
              <td key={idx} className={`p-6 text-sm font-mono text-gray-300 ${card.matchScore === highestMatch ? 'bg-indigo-500/5' : ''}`}>
                  {card.minCreditScore}
              </td>
