  console.log("⚠️ Using Smart Fallback Engine (API Key missing or call failed)");

  // 1. Filter by Income Eligibility
  let eligibleCards = CARD_POOL.filter(c => c.minIncome <= profile.annualIncome);

  // Fallback if income is too low for any premium cards (ensure at least 4 cards)
  if (eligibleCards.length < 4) {
    eligibleCards = CARD_POOL.slice(0, 4); // Just give the basic ones
  }

  // 2. Score Cards based on User Preferences
  const scoredCards = eligibleCards.map(card => {
    let score = 75; // Base score

    // Category Match
    const categoryMatches = profile.topCategories.some(userCat => 
      card.type.some(cardType => userCat.toLowerCase().includes(cardType) || cardType.includes(userCat.toLowerCase()))
    );
    if (categoryMatches) score += 15;

    // Income "Sweet Spot" (Don't recommend entry cards to millionaires)
    if (profile.annualIncome > 1500000 && card.minIncome < 500000) score -= 10;
    if (profile.annualIncome > 1500000 && card.minIncome > 1000000) score += 10;

    // Goal Match
    if (profile.primaryGoal === 'travel' && card.type.includes('travel')) score += 10;
    if (profile.primaryGoal === 'cashback' && card.type.includes('cashback')) score += 10;
    if (profile.primaryGoal === 'luxury' && card.type.includes('luxury')) score += 10;

    // Cap score at 99
    score = Math.min(99, Math.max(60, score));

    // Generate Dynamic Reasoning
    const dynamicReasoning = `Selected because it fits your ₹${(profile.monthlySpend/1000).toFixed(0)}k monthly spend and excels in ${card.type[0]}. Good match for your ${profile.primaryGoal} goal.`;

    return { ...card, matchScore: score, reasoning: dynamicReasoning };
  });

  // 3. Sort by Score and return top 4
  return scoredCards
    .sort((a, b) => b.matchScore - a.matchScore)
    .slice(0, 4);
};

export const getRecommendations = async (profile: UserProfile): Promise<CreditCardRecommendation[]> => {
  const model = "gemini-3-flash-preview";

  // Debug Log for user
  if (!apiKey || apiKey === "dummy_key") {
    console.warn("NovaFin: No valid API_KEY found. Using Smart Fallback. Please add API_KEY to your environment variables.");
    // Simulate network delay for realism
    await new Promise(r => setTimeout(r, 1000));
    return getSmartFallback(profile);
  }

  const prompt = `
    Act as a senior financial analyst for the Indian market.
    Analyze the following user profile:
    - Name: ${profile.name}
    - Annual Income: ₹${profile.annualIncome} (converted to INR context)
    - Credit Score: ${profile.creditScore}
    - Monthly Spending: ₹${profile.monthlySpend}
    - Top Spending Categories: ${profile.topCategories.join(', ')}
    - Primary Goal: ${profile.primaryGoal}

    Recommend exactly 4 distinct credit cards from major RBI-registered banks (e.g., HDFC, SBI, ICICI, Axis, Amex India, Kotak).

    For each card:
    1. Provide detailed comparison metrics.
    2. Provide a realistic direct application link or official product page URL for 'applyLink'.

    Provide the response strictly in JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              cardName: { type: Type.STRING },
              bankName: { type: Type.STRING },
              matchScore: { type: Type.NUMBER, description: "Percentage match 0-100" },
              annualFee: { type: Type.STRING, description: "e.g. ₹499 + GST" },
              features: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              colorTheme: { type: Type.STRING, description: "Hex color code" },
              reasoning: { type: Type.STRING },
              loungeAccess: { type: Type.STRING, description: "Short summary of airport lounge access" },
              rewardRate: { type: Type.STRING, description: "e.g. '3.3% on Travel'" },
              welcomeBonus: { type: Type.STRING, description: "Short summary of welcome gift" },
              minCreditScore: { type: Type.STRING, description: "Minimum recommended score e.g. '750+'" },
              applyLink: { type: Type.STRING, description: "URL to the bank's card application page" }
            },
            required: [
              "cardName", "bankName", "matchScore", "annualFee", "features", 
              "colorTheme", "reasoning", "loungeAccess", "rewardRate", 
              "welcomeBonus", "minCreditScore", "applyLink"
            ]
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    const result = JSON.parse(jsonText) as CreditCardRecommendation[];

    if (!result || result.length === 0) {
      throw new Error("Empty response from AI");
    }
    return result;

  } catch (error) {
    console.error("NovaFin AI Error:", error);
    // Gracefully fallback to Smart Local Logic
    return getSmartFallback(profile); 
  }
};

import React from 'react';
import { CreditCardRecommendation } from '../types';
import { Trophy, Crown, CheckCircle2 } from 'lucide-react';

interface ComparisonTableProps {
  cards: CreditCardRecommendation[];
}

export const ComparisonTable: React.FC<ComparisonTableProps> = ({ cards }) => {
  if (!cards || cards.length === 0) return null;

  // Find the highest match score numeric value
  const maxScore = Math.max(...cards.map(c => c.matchScore));

  // Identify the FIRST card that has this score to avoid double highlighting if there's a tie
  const bestCardIndex = cards.findIndex(c => c.matchScore === maxScore);

  const highlightText = (text: string) => {
    // Keywords that indicate value to the user
    const keywords = [
      'lifetime free', 'unlimited', 'free', 'bonus', 'complementary', '0 joining', '5x', '10x', '12', '25,000', 'priority pass'
    ];
    const lowerText = text.toLowerCase();

    const containsKeyword = keywords.some(k => lowerText.includes(k));

    if (containsKeyword) {
      return <span className="text-green-400 font-bold drop-shadow-[0_0_8px_rgba(74,222,128,0.3)]">{text}</span>;
    }
    return <span className="text-gray-300">{text}</span>;
  };

  return (
    <div className="w-full overflow-x-auto rounded-3xl glass-panel border border-white/10 scrollbar-thin scrollbar-thumb-indigo-500/20 scrollbar-track-transparent shadow-2xl pt-20">
      <table className="w-full text-left border-collapse min-w-[900px]">
        <thead>
          <tr className="border-b border-white/10">
            <th className="p-6 text-gray-400 font-medium w-1/5 bg-white/5 sticky left-0 backdrop-blur-xl z-10 border-r border-white/5">
                <span className="uppercase tracking-widest text-xs font-bold">Parameters</span>
            </th>
            {cards.map((card, idx) => (
              <th key={idx} className={`p-6 w-1/5 relative transition-all duration-300 ${idx === bestCardIndex ? 'bg-gradient-to-b from-yellow-500/10 to-transparent border-t-2 border-yellow-500' : ''}`}>
                {idx === bestCardIndex && (
                  <div className="absolute -top-12 left-1/2 -translate-x-1/2 px-4 py-1.5 bg-yellow-500 text-black text-[10px] font-bold rounded-full flex items-center gap-1.5 shadow-[0_0_20px_rgba(234,179,8,0.5)] z-20 whitespace-nowrap">
                     <Crown className="w-3.5 h-3.5 fill-black" />
                     BEST MATCH
                  </div>
                )}
                <div className={`flex flex-col gap-2 mt-2 transition-transform duration-300 ${idx === bestCardIndex ? 'scale-105 origin-top' : ''}`}>
                    <span className="text-xs font-mono text-indigo-400 tracking-wider uppercase">{card.bankName}</span>
                    <span className={`text-xl font-bold leading-tight ${idx === bestCardIndex ? 'text-yellow-400' : 'text-white'}`}>
                        {card.cardName}
                    </span>
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-white/5">
          {/* Annual Fee */}
          <tr className="hover:bg-white/5 transition-colors group">
            <td className="p-6 font-medium text-gray-300 bg-slate-900/50 sticky left-0 backdrop-blur-xl border-r border-white/5 z-10">Annual Fee</td>
            {cards.map((card, idx) => (
              <td key={idx} className={`p-6 text-sm relative ${idx === bestCardIndex ? 'bg-yellow-500/5' : ''}`}>
                 {idx === bestCardIndex && <div className="absolute inset-0 border-x border-yellow-500/10 pointer-events-none"></div>}
                 {highlightText(card.annualFee)}
              </td>
            ))}
          </tr>

          {/* Match Score */}
          <tr className="hover:bg-white/5 transition-colors group">
            <td className="p-6 font-medium text-gray-300 bg-slate-900/50 sticky left-0 backdrop-blur-xl border-r border-white/5 z-10">AI Match Score</td>
            {cards.map((card, idx) => (
