const getSmartFallback = (profile: UserProfile): CreditCardRecommendation[] => {
  console.log("⚠️ NovaFin: Using Offline Smart Fallback Engine");

  // 1. Filter by Income Eligibility
  let eligibleCards = CARD_POOL.filter(c => c.minIncome <= profile.annualIncome);

  // Fallback if income is too low for premium cards (ensure user always gets results)
  if (eligibleCards.length < 4) {
    eligibleCards = CARD_POOL.slice(0, 4);
  }

  // 2. Score Cards based on User Preferences
  const scoredCards = eligibleCards.map(card => {
    let score = 75; // Base score

    // Category Match
    const categoryMatches = profile.topCategories.some(userCat => 
      card.type.some(cardType => userCat.toLowerCase().includes(cardType) || cardType.includes(userCat.toLowerCase()))
    );
    if (categoryMatches) score += 15;

    // Income "Sweet Spot" Logic
    if (profile.annualIncome > 1500000 && card.minIncome < 500000) score -= 10;
    if (profile.annualIncome > 1500000 && card.minIncome > 1000000) score += 10;

    // Goal Match
    if (profile.primaryGoal === 'travel' && card.type.includes('travel')) score += 10;
    if (profile.primaryGoal === 'cashback' && card.type.includes('cashback')) score += 10;
    if (profile.primaryGoal === 'luxury' && card.type.includes('luxury')) score += 10;

    // Cap score at 99, min 60
    score = Math.min(99, Math.max(60, score));

    // Generate Dynamic Reasoning
    const dynamicReasoning = `Based on your ${profile.primaryGoal} focus and ₹${(profile.monthlySpend/1000).toFixed(0)}k monthly spend, this card offers optimal value in ${card.type[0]}.`;

    return { ...card, matchScore: score, reasoning: dynamicReasoning };
  });

  // 3. Sort by Score and return top 4
  return scoredCards
    .sort((a, b) => b.matchScore - a.matchScore)
    .slice(0, 4);
};

export const getRecommendations = async (profile: UserProfile): Promise<CreditCardRecommendation[]> => {
  // Check key validity at runtime
  if (!apiKey || apiKey === "dummy_key_init") {
    console.warn("NovaFin: No valid API_KEY found. Falling back to internal engine.");
    // Simulate network latency for realism
    await new Promise(r => setTimeout(r, 1500));
    return getSmartFallback(profile);
  }

  const ai = getAIClient();
  const model = "gemini-3-flash-preview";

  const prompt = `
    Act as a senior financial analyst for the Indian market.
    Analyze the following user profile:
    - Name: ${profile.name}
    - Annual Income: ₹${profile.annualIncome} (converted to INR context)
    - Credit Score: ${profile.creditScore}
    - Monthly Spending: ₹${profile.monthlySpend}
    - Top Spending Categories: ${profile.topCategories.join(', ')}
    - Primary Goal: ${profile.primaryGoal}

    Recommend exactly 4 distinct credit cards from major RBI-registered banks (e.g., HDFC, SBI, ICICI, Axis, Amex India, Kotak).
    For each card provide detailed comparison metrics.
    Provide the response strictly in JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              cardName: { type: Type.STRING },
              bankName: { type: Type.STRING },
              matchScore: { type: Type.NUMBER },
              annualFee: { type: Type.STRING },
              features: { type: Type.ARRAY, items: { type: Type.STRING } },
              colorTheme: { type: Type.STRING },
              reasoning: { type: Type.STRING },
              loungeAccess: { type: Type.STRING },
              rewardRate: { type: Type.STRING },
              welcomeBonus: { type: Type.STRING },
              minCreditScore: { type: Type.STRING },
              applyLink: { type: Type.STRING }
            },
            required: [
              "cardName", "bankName", "matchScore", "annualFee", "features", 
              "colorTheme", "reasoning", "loungeAccess", "rewardRate", 
              "welcomeBonus", "minCreditScore", "applyLink"
            ]
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    const result = JSON.parse(jsonText) as CreditCardRecommendation[];

    if (!result || result.length === 0) throw new Error("Empty response");
    return result;

  } catch (error) {
    console.error("NovaFin AI Error:", error);
    return getSmartFallback(profile); 
  }
};

import React, { useRef, useState, MouseEvent } from 'react';

interface TiltCardProps {
  children: React.ReactNode;
  className?: string;
  glowColor?: string;
}

export const TiltCard: React.FC<TiltCardProps> = ({ children, className = "", glowColor = "rgba(99, 102, 241, 0.4)" }) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [rotation, setRotation] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;

    const rect = cardRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    const rotateX = ((y - centerY) / centerY) * -10; // Invert X axis for correct tilt
    const rotateY = ((x - centerX) / centerX) * 10;

    setRotation({ x: rotateX, y: rotateY });
  };

  const handleMouseEnter = () => setIsHovered(true);
  const handleMouseLeave = () => {
    setIsHovered(false);
    setRotation({ x: 0, y: 0 });
  };

  return (
    <div
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className={`relative transition-all duration-200 ease-out transform-gpu ${className}`}
      style={{
        perspective: "1000px",
      }}
    >
      <div
        className="w-full h-full transition-transform duration-200 ease-out"
        style={{
          transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg) scale(${isHovered ? 1.05 : 1})`,
          transformStyle: "preserve-3d",
        }}
      >
        <div 
          className="absolute inset-0 rounded-2xl opacity-0 transition-opacity duration-300 pointer-events-none z-0"
          style={{
             opacity: isHovered ? 1 : 0,
             background: `radial-gradient(circle at 50% 50%, ${glowColor}, transparent 70%)`,
             filter: 'blur(20px)',
             transform: 'translateZ(-20px)'
          }}
        />
        <div className="relative z-10 h-full">
           {children}
        </div>

        {/* Gloss overlay */}
        <div 
            className="absolute inset-0 rounded-2xl pointer-events-none z-20 mix-blend-overlay"
            style={{
                background: `linear-gradient(125deg, rgba(255,255,255,0.4) 0%, transparent 40%, transparent 60%, rgba(255,255,255,0.1) 100%)`,
                opacity: isHovered ? 0.3 : 0,
                transition: 'opacity 0.3s ease'
            }}
        />
      </div>
    </div>
  );
};

